import {Component, inject} from '@angular/core';
import {CartStore} from './cart-store';

@Component({
  selector: 'cart-display',
  template: `
    <div class="cart-display">
      <h2>Shopping Cart Demo</h2>

      <!-- Add some products to test the cart -->
      <div class="add-products">
        <h3>Add Products</h3>
        <button (click)="addLaptop()">Add Laptop ($999)</button>
        <button (click)="addMouse()">Add Mouse ($25)</button>
        <button (click)="addKeyboard()">Add Keyboard ($79)</button>
      </div>

      <h3>Cart Contents</h3>
      @if (cartStore.cartItems().length === 0) {
        <p class="empty-message">Your cart is empty</p>
      } @else {
        <div class="cart-items">
          @for (item of cartStore.cartItems(); track item.id) {
            <div class="cart-item">
              <div class="item-info">
                <h4>{{ item.name }}</h4>
                <p class="price">\${{ item.price }} each</p>
              </div>

              <div class="quantity-controls">
                <button (click)="decreaseQuantity(item.id)">-</button>
                <span class="quantity">{{ item.quantity }}</span>
                <button (click)="increaseQuantity(item.id)">+</button>
                <button (click)="removeItem(item.id)" class="remove">×</button>
              </div>
            </div>
          }
        </div>

        <div class="cart-summary">
          <p>Total Items: {{ cartStore.totalQuantity() }}</p>
          <p class="total-price">Total: \${{ cartStore.totalPrice() }}</p>
          <button (click)="clearCart()" class="clear-btn">Clear Cart</button>
        </div>
      }
    </div>
  `,
})
export class CartDisplay {
  cartStore = inject(CartStore);

  addLaptop() {
    this.cartStore.addItem('1', 'Laptop', 999);
  }

  addMouse() {
    this.cartStore.addItem('2', 'Mouse', 25);
  }

  addKeyboard() {
    this.cartStore.addItem('3', 'Keyboard', 79);
  }

  increaseQuantity(id: string) {
    // TODO: Get current item from cartStore.cartItems()
    // and call cartStore.updateQuantity() with quantity + 1
  }

  decreaseQuantity(id: string) {
    // TODO: Get current item from cartStore.cartItems()
    // and call cartStore.updateQuantity() with quantity - 1 (if > 1)
  }

  removeItem(id: string) {
    this.cartStore.removeItem(id);
  }

  clearCart() {
    this.cartStore.clearCart();
  }
}

@use '../../../styles/typography';

:host {
  display: flex;
  flex-direction: column;
  height: 100%;

  .filter {
    border-bottom: 1px solid var(--color-separator);
    display: flex;
    gap: 1.25rem;
    padding: 0.5rem;

    .filter-input {
      width: 12rem;
    }

    .show-full-path {
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
  }

  .visualization {
    position: relative;
    overflow: hidden;
    flex: 1;

    .side-pane {
      position: relative;
      display: flex;
      flex-direction: column;
      height: 100%;

      .close-btn {
        position: absolute;
        top: 1rem;
        right: 1rem;

        mat-icon {
          font-size: 16px;
          width: 16px;
          height: 16px;
        }
      }

      h2 {
        @extend %heading-400;
        margin: 0;
        padding-top: 0;
        padding: 1rem;
      }

      .scrollable-wrapper {
        padding: 0 1rem 1rem 1rem;
        height: 100%;
        overflow-y: auto;
      }
    }

    .legend {
      position: absolute;
      bottom: 0.75rem;
      left: 0.75rem;
      padding: 0.5rem;
      border-radius: 0.5rem;
      background-color: color-mix(in srgb, var(--color-background) 80%, transparent 20%);
      backdrop-filter: blur(8px);

      ul {
        list-style-type: none;
        padding: 0;
        margin: 0;

        li {
          margin: 0;
          display: flex;
          align-items: center;
          gap: 0.375rem;
          color: var(--tertiary-contrast);

          &:not(:last-child) {
            margin-bottom: 0.75rem;
          }

          &::before {
            content: '';
            display: block;
            width: 12px;
            height: 12px;
            border: 1px solid;
          }

          &.eager::before {
            border-color: var(--red-05);
            background-color: var(--red-06);
          }

          &.lazy::before {
            border-color: var(--blue-02);
            background-color: var(--blue-03);
          }

          &.active::before {
            border-color: var(--green-02);
            background-color: var(--green-03);
          }
        }
      }
    }
  }
}

.unsupported-version {
